Object.assign(VERIFIED_ANSWERS,{
  'ch12-problem-001':{status:'verified',confidence:'high',answer:`a. χ² = 18.4232.\nb. df=2, p≈0.00010; reject H₀.\nc. χ².05,2=5.991; 18.4232>5.991, reject H₀.`,explanation:`H₀: the candidate proportions remain 34%, 43%, and 23%. Expected counts are 136, 172, and 92. χ²=Σ(O−E)²/E=18.4232. The campaign-period sample provides strong evidence that the preference proportions changed.`},
  'ch12-problem-003':{status:'verified',confidence:'high',answer:`H₀: illness is independent of smoking. H₁: they are not independent.\nExpected table: (32,48), (60,90), (28,42).\nχ²=10.5159, df=2, p≈0.0052. Reject H₀ at α=.05.`,explanation:`Each expected count is row total × column total / 300. Since 10.5159>χ².05,2=5.991, illness type and smoking status are associated in this sample. Association alone does not establish causation.`},
  'ch13-problem-020':{status:'verified',confidence:'high',answer:`H₀: μA=μB=μC=μD; H₁: not all means are equal.\nMeans: 145, 135, 190, 150; grand mean=155.\nSSTR=8,750; SSE=7,600; SST=16,350.\nANOVA: treatment df=3, MSTR=2,916.667; error df=16, MSE=475; F=6.1404; p≈.0056. Reject H₀.\nFisher LSD=29.22. C differs from A, B, and D; the other pairs do not differ significantly.`,explanation:`The overall F test must be significant before the protected LSD comparisons. Program C has the highest mean output and is the only program separated from each of the other three by more than the LSD.`},
  'ch14-problem-001':{status:'verified',confidence:'high',answer:`a. ŷ=1.04155+0.00990716x.\nb. R²=0.56291: about 56.29% of sample price variation is explained by pages.\nc. r=0.75027; t=2.5376 (df=5), equivalent F=6.4392. At α=.10, reject H₀:β₁=0.`,explanation:`The slope is positive: one additional page is associated with about $0.00991 higher predicted price within the observed range. This is association, not a causal conclusion.`},
  'ch14-problem-003':{status:'verified',confidence:'high',answer:`a. ŷ=29.78571−0.728571x; each $1 increase in price is associated with about 0.729 fewer units sold.\nb. R²=0.85559.\nc. r=−0.92498; t=−5.4428 (df=5), F=29.6241. At α=.01, reject H₀:β₁=0.`,explanation:`The fitted relationship is strong and negative. The sign of r follows the sign of the slope, and r² equals R² in simple regression.`},
  'ch15-problem-006':{status:'verified',confidence:'high',answer:`a. ŷ=7.0174+8.6233X₁+0.0858X₂.\nb. At X₁=3.5 and X₂=45: ŷ=41.05995 million dollars = $41,059,950.\nc. F=17.7297 with df=(2,7); the overall model is significant at α=.05.\nd. t for β₁=3.5978 with df=7; advertising is significant.\ne. R²=321.11/(321.11+63.39)=0.83514.\nf. Adjusted R²=0.78803.`,explanation:`The overall F asks whether all slopes are zero jointly. The individual advertising t test asks whether β₁ is zero while holding the number of salespeople constant.`},
  'ch16-problem-010':{status:'verified',confidence:'high',answer:`Partial F=[(1425−1300)/1]/[1300/(28−3−1)]=2.3077. With df=(1,24), p≈.142; do not reject H₀ at α=.05. Do not add X₃ solely on this evidence.`,explanation:`The full model contains three predictors, so its error df is 28−3−1=24. The decrease in SSE is not large enough relative to the full-model error variance.`},
  'ch17-problem-002':{status:'verified',confidence:'high',answer:`Weights from oldest to newest are 2,3,5.\nApril=50.0; May=56.1; June=66.9; July=78.0.`,explanation:`For July: [2(60)+3(75)+5(87)]/10=78. The largest weight must be assigned to the most recent month.`},
  'ch17-problem-005':{status:'verified',confidence:'high',answer:`With α=.2 and FJan=18:\nFFeb=18.00; FMar=19.00; FApr=19.20; FMay=18.56.`,explanation:`Use F(t+1)=αA(t)+(1−α)F(t). The April actual value is used to create the May forecast, not the April forecast.`},
  'ch18-problem-001':{status:'verified',confidence:'high',answer:`Exclude 10 no-preference responses: n=390.\nH₀:p=.5; H₁:p≠.5.\nμ=np=195; σ=√[np(1−p)]=√97.5=9.8742.\nz≈(250−195)/9.8742=5.570 (5.52 with continuity correction). Reject H₀.`,explanation:`The evidence shows a difference in preference, with domestic wine preferred more often. Ties are excluded from the sign-test sample size.`},
  'ch18-problem-008':{status:'verified',confidence:'high',answer:`Rank differences are 1, −2, −1, 0, 2; Σd²=10.\nrₛ=1−6(10)/[5(5²−1)]=0.50. The correlation is not significant at α=.05 for n=5.`,explanation:`The two employers have a moderate positive rank association, but five candidates provide insufficient evidence for statistical significance.`}
});

const addProblem=(chapter,number,answer,explanation)=>{
  VERIFIED_ANSWERS[`ch${chapter}-problem-${String(number).padStart(3,'0')}`]={status:'verified',confidence:'high',answer,explanation};
};
const chiLine=(x,df,p,alpha,critical,reject)=>`χ²=${x}; df=${df}; p=${p}; χ² critical (${alpha})=${critical}. ${(reject===true||reject==='true')?'Reject H₀.':'Do not reject H₀.'}`;

// Chapter 12 problems: every expected count and chi-square contribution was
// recomputed. Poisson tails were pooled where required to keep E >= 5. Normal
// GOF items use equal-probability intervals, matching the source item design.
addProblem(12,2,`H₀: audience proportions remain 31%, 34%, and 35%; H₁: at least one changed.\nExpected: 186, 204, 210.\n${chiLine('14.6652',2,'0.000654','.05','5.991','true')}`,`The observed network shares differ significantly from the recorded proportions.`);
addProblem(12,4,`${chiLine('5.2525',2,'0.07235','.10','4.605','true')}`,`H₀ states that management position is independent of major. At α=.10, the evidence indicates an association.`);
addProblem(12,5,`H₀: station preference is independent of education; H₁: they are associated.\nExpected table: (70,140,70), (130,260,130).\n${chiLine('12.0879',2,'0.002372','.05','5.991','true')}`,`Station selection and education level are not independent in this sample.`);
addProblem(12,6,`Expected medals: 30, 26.4, 21.6, 16.8, 13.2, 12.\n${chiLine('7.6929',5,'0.173995','.05','11.070','false')}`,`The midway medal distribution is consistent with the expected percentages.`);
addProblem(12,7,`Uniform expected frequency: 154/7=22 each day.\n${chiLine('23.2727',6,'0.000710','.05','12.592','true')}`,`Cardiac deaths are not uniformly distributed across the days of the week.`);
addProblem(12,8,`Expected: 576, 456, 48, 120.\n${chiLine('8.1798',3,'0.04244','.05','7.815','true')}`,`The post-debate voter proportions differ significantly from the pre-debate proportions.`);
addProblem(12,9,`Expected: 90, 72, 78, 60.\n${chiLine('1.6615',3,'0.64552','.05','7.815','false')}`,`There is no statistically significant change in the distribution of majors.`);
addProblem(12,10,`Uniform expected frequency: 15 per season.\n${chiLine('8.4000',3,'0.03843','.05','7.815','true')}`,`Resignations are not uniform across the four seasons.`);
addProblem(12,11,`Expected counts under the 2002 proportions: 240 Business, 210 Engineering, 150 Other.\n${chiLine('13.1429',2,'0.001400','.05','5.991','true')}`,`The 2003 proportions differ significantly from the 2002 proportions.`);
addProblem(12,12,`Equal-share expected counts: 50, 50, 50.\n${chiLine('3.7200',2,'0.15567','.05','5.991','false')}`,`The Christmas sample does not show a significant change in payment methods.`);
addProblem(12,13,`Equal expected repair frequencies: 40 per model.\n${chiLine('4.2500',4,'0.37323','.05','9.488','false')}`,`The sample does not contradict the manufacturer's equal-frequency claim.`);
addProblem(12,14,`H₀: values 0-4 are equally likely; H₁: they are not equally likely.\nExpected: 50 each.\n${chiLine('5.0000',4,'0.28730','.05','9.488','false')}`,`There is insufficient evidence that the lottery is unfair.`);
addProblem(12,15,`H₀: age shares remain 40%, 45%, 15%; H₁: at least one share changed.\nExpected: 120, 135, 45.\n${chiLine('5.5556',2,'0.06218','.01','9.210','false')}`,`At the 1% level, the market shares have not changed significantly.`);
addProblem(12,16,`${chiLine('7.1111',2,'0.02857','.10','4.605','true')}`,`H₀ states that field of study and gender are independent. They are associated at α=.10.`);
addProblem(12,17,`Expected table: (425,325), (340,260), (85,65).\n${chiLine('20.3620',2,'0.0000379','.05','5.991','true')}`,`The row and column factors are not independent.`);
addProblem(12,18,`Expected table: A=(40,60,100), B=(60,90,150).\n${chiLine('4.4444',2,'0.10837','.05','5.991','false')}`,`The sample does not provide evidence of dependence between the factors.`);
addProblem(12,19,`Expected table: (16,24), (20,30), (24,36).\n${chiLine('28.1250',2,'0.000000781','.05','5.991','true')}`,`Yearly income category is associated with gender.`);
addProblem(12,20,`Expected table: Domestic=(80,320,400), Foreign=(120,480,600).\n${chiLine('135.0000',2,'4.84×10⁻³⁰','.05','5.991','true')}`,`Type of car purchased is strongly associated with city.`);
addProblem(12,21,`Expected table: (60,40), (120,80).\n${chiLine('25.0000',1,'0.000000573','.05','3.841','true')}`,`Weight loss is not independent of taking the diet pills; this is association, not by itself proof of causation.`);
addProblem(12,22,`H₀: purchase reason is independent of gender; H₁: they are associated.\nExpected table: Male=(70,105,175), Female=(30,45,75).\n${chiLine('31.7460',2,'0.000000128','.01','9.210','true')}`,`Main purchase reason depends on gender in this sample.`);
