addProblem(12,26,`${chiLine('8.6738',12,'0.73051','.05','21.026','false')}`,`The regional distributions of fields of specialization do not differ significantly.`);
addProblem(12,27,`Sample mean λ̂=3.500 calls. Pool 0-1 and use 7+ for the upper tail.\nExpected: 20.3832, 27.7438, 32.3678, 28.3218, 19.8253, 11.5648, 9.7932.\n${chiLine('10.3228',5,'0.06659','.05','11.070','false')}`,`After estimating one Poisson parameter, df=7−1−1=5. The Poisson model is not rejected.`);
